#include "clustering/ModifiedBestChoiceClusterer.h"
#include <algorithm>
#include <queue>
static ClusterCandidate makeC(const DynamicClusterHypergraph&h,int o,const BestNeighbor&b){int a=std::min(o,b.cluster), c=std::max(o,b.cluster); return {a,c,o,b.cluster,b.score,h.clusters()[a].version,h.clusters()[c].version};}
std::vector<ClusterCandidate> ModifiedBestChoiceClusterer::initialCandidates(DynamicClusterHypergraph& h)const{std::vector<ClusterCandidate> out; for(auto& c:h.clusters()) if(c.active&&c.movable){auto b=h.findMaximumScoreNeighbor(c.id); if(b) out.push_back(makeC(h,c.id,*b)); c.valid=true;} std::sort(out.begin(),out.end(),[](auto&a,auto&b){return ClusterCandidateLess{}(b,a);}); return out;}
ClustererStats ModifiedBestChoiceClusterer::cluster(DynamicClusterHypergraph& h,int target){ClustererStats st; st.input_movable_clusters=h.activeMovableClusterCount(); st.target_movable_clusters=target; std::priority_queue<ClusterCandidate,std::vector<ClusterCandidate>,ClusterCandidateLess> pq; for(auto& c:initialCandidates(h)) pq.push(c); auto reinsert=[&](int j){auto b=h.findMaximumScoreNeighbor(j); if(b) pq.push(makeC(h,j,*b)); h.clusters()[j].valid=true; st.invalid_recomputations++;}; while(h.activeMovableClusterCount()>target){if(pq.empty()){st.stop_reason="nonpositive_or_no_candidate"; st.top_score_at_stop=0; break;} auto cand=pq.top(); if(cand.score<=0){st.stop_reason="stopped_by_nonpositive_score"; st.top_score_at_stop=cand.score; break;} pq.pop(); int j=cand.owner_cluster,k=cand.partner_cluster; if(j<0||j>=(int)h.clusters().size()||!h.clusters()[j].active) continue; int a=cand.first_cluster,b=cand.second_cluster; bool stale=k<0||k>=(int)h.clusters().size()||!h.clusters()[k].active||!h.clusters()[k].movable||a>=(int)h.clusters().size()||b>=(int)h.clusters().size()||h.clusters()[a].version!=cand.first_version||h.clusters()[b].version!=cand.second_version; if(stale){h.clusters()[j].valid=false; st.stale_candidates++; reinsert(j); continue;} if(!h.clusters()[j].valid){reinsert(j); continue;} int new_id=h.mergeClusters(j,k); st.positive_score_merges++; st.merge_sequence.push_back({j,k}); auto nb=h.findMaximumScoreNeighbor(new_id); if(nb) pq.push(makeC(h,new_id,*nb)); h.clusters()[new_id].valid=true; }
 if(st.stop_reason.empty()) st.stop_reason="stopped_by_target"; st.output_movable_clusters=h.activeMovableClusterCount(); return st;}
